-- =================================================================
-- YoY per-channel NET SALES  (restores data lost by supabase_yoy_epos.sql)
--
-- migration 010 loaded per-channel REVENUE into click_collect / kiosk /
-- till_eat_in / till_takeaway / deliveroo / just_eat / uber_eats.
-- supabase_yoy_epos.sql then INSERT..ON CONFLICT DO UPDATE the SAME columns
-- with EPOS ORDER COUNTS, overwriting the revenue.
--
-- This script adds dedicated *_sales columns and reloads the revenue from the
-- original Excel exports, leaving the order-count columns untouched so nothing
-- that depends on them changes. own_delivery_sales already exists and was never
-- overwritten, so it is not re-seeded.
--
-- Verified before generating: for all 324 week-rows across the three files,
--   deliveroo + just_eat + uber_eats                        = aggregate_sales
--   click_collect + kiosk + till_eat_in + till_takeaway     = in_store_sales
--   own_delivery                                            = own_delivery_sales
-- to within 2p. Re-runnable (idempotent upsert).
-- =================================================================

-- vm_yoy_both_stores: add per-channel sales columns
ALTER TABLE vm_yoy_both_stores ADD COLUMN IF NOT EXISTS click_collect_sales NUMERIC;
ALTER TABLE vm_yoy_both_stores ADD COLUMN IF NOT EXISTS kiosk_sales NUMERIC;
ALTER TABLE vm_yoy_both_stores ADD COLUMN IF NOT EXISTS till_eat_in_sales NUMERIC;
ALTER TABLE vm_yoy_both_stores ADD COLUMN IF NOT EXISTS till_takeaway_sales NUMERIC;
ALTER TABLE vm_yoy_both_stores ADD COLUMN IF NOT EXISTS deliveroo_sales NUMERIC;
ALTER TABLE vm_yoy_both_stores ADD COLUMN IF NOT EXISTS just_eat_sales NUMERIC;
ALTER TABLE vm_yoy_both_stores ADD COLUMN IF NOT EXISTS uber_eats_sales NUMERIC;

-- vm_yoy_hitchin: add per-channel sales columns
ALTER TABLE vm_yoy_hitchin ADD COLUMN IF NOT EXISTS click_collect_sales NUMERIC;
ALTER TABLE vm_yoy_hitchin ADD COLUMN IF NOT EXISTS kiosk_sales NUMERIC;
ALTER TABLE vm_yoy_hitchin ADD COLUMN IF NOT EXISTS till_eat_in_sales NUMERIC;
ALTER TABLE vm_yoy_hitchin ADD COLUMN IF NOT EXISTS till_takeaway_sales NUMERIC;
ALTER TABLE vm_yoy_hitchin ADD COLUMN IF NOT EXISTS deliveroo_sales NUMERIC;
ALTER TABLE vm_yoy_hitchin ADD COLUMN IF NOT EXISTS just_eat_sales NUMERIC;
ALTER TABLE vm_yoy_hitchin ADD COLUMN IF NOT EXISTS uber_eats_sales NUMERIC;

-- vm_yoy_stevenage: add per-channel sales columns
ALTER TABLE vm_yoy_stevenage ADD COLUMN IF NOT EXISTS click_collect_sales NUMERIC;
ALTER TABLE vm_yoy_stevenage ADD COLUMN IF NOT EXISTS kiosk_sales NUMERIC;
ALTER TABLE vm_yoy_stevenage ADD COLUMN IF NOT EXISTS till_eat_in_sales NUMERIC;
ALTER TABLE vm_yoy_stevenage ADD COLUMN IF NOT EXISTS till_takeaway_sales NUMERIC;
ALTER TABLE vm_yoy_stevenage ADD COLUMN IF NOT EXISTS deliveroo_sales NUMERIC;
ALTER TABLE vm_yoy_stevenage ADD COLUMN IF NOT EXISTS just_eat_sales NUMERIC;
ALTER TABLE vm_yoy_stevenage ADD COLUMN IF NOT EXISTS uber_eats_sales NUMERIC;

-- ---------------------------------------------------------------
-- vm_yoy_both_stores: 108 weeks of per-channel net sales
-- ---------------------------------------------------------------
ON CONFLICT (week_commencing) DO UPDATE SET
  click_collect_sales = EXCLUDED.click_collect_sales,
  kiosk_sales = EXCLUDED.kiosk_sales,
  till_eat_in_sales = EXCLUDED.till_eat_in_sales,
  till_takeaway_sales = EXCLUDED.till_takeaway_sales,
  deliveroo_sales = EXCLUDED.deliveroo_sales,
  just_eat_sales = EXCLUDED.just_eat_sales,
  uber_eats_sales = EXCLUDED.uber_eats_sales;

